fun solve(grid: Array<Array<Long>>, k: Long): Long {
    val m = grid.size
    val n = grid[0].size
    var count = 0L

    for (i in 0 until m) {
        for (j in 0 until n) {
            if (grid[i][j] > 0) {
                val queue = LinkedList<Pair<Int, Int>>()
                queue.add(Pair(i, j))
                grid[i][j] = 0L
                var sum = grid[i][j]
                val directions = arrayOf(intArrayOf(-1, 0), intArrayOf(1, 0), intArrayOf(0, -1), intArrayOf(0, 1))
                while (queue.isNotEmpty()) {
                    val (x, y) = queue.removeFirst()
                    for (dir in directions) {
                        val dx = dir[0]
                        val dy = dir[1]
                        val nx = x + dx
                        val ny = y + dy
                        if (nx in 0 until m && ny in 0 until n && grid[nx][ny] > 0) {
                            grid[nx][ny] = 0L
                            sum += grid[nx][ny]
                            queue.add(Pair(nx, ny))
                        }
                    }
                }
                if (sum % k == 0) {
                    count++
                }
            }
        }
    }
    return count
}
